import{c as a,Q as e,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"6/ Software 3.0: what can now exist that literally could not before? — @stephzhan","description":"","frontmatter":{"title":"6/ Software 3.0: what can now exist that literally could not before? — @stephzhan","author":"Stephanie Zhan（@stephzhan）","date":"2026-04-29T00:00:00.000Z","source":"https://x.com/stephzhan/status/2049518672352587987","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-29-@stephzhan-587987.md","filePath":"research/tweets/2026-04-29-@stephzhan-587987.md","lastUpdated":1779894392000}'),s={name:"research/tweets/2026-04-29-@stephzhan-587987.md"};function n(h,t,l,d,i,p){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="_6-software-3-0-what-can-now-exist-that-literally-could-not-before-—-stephzhan" tabindex="-1">6/ Software 3.0: what can now exist that literally could not before? — @stephzhan <a class="header-anchor" href="#_6-software-3-0-what-can-now-exist-that-literally-could-not-before-—-stephzhan" aria-label="Permalink to &quot;6/ Software 3.0: what can now exist that literally could not before? — @stephzhan&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/stephzhan/status/2049518672352587987" target="_blank" rel="noreferrer">https://x.com/stephzhan/status/2049518672352587987</a><strong>作者</strong>：Stephanie Zhan（@stephzhan） <strong>發布日期</strong>：2026-04-29 <strong>收錄日期</strong>：2026-05-01 <strong>類型</strong>：推文 <strong>統計</strong>：25 likes · 1 retweets · 12 bookmarks · 2644 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>6/ AI is not just &quot;better software.&quot;</p><p>Karpathy&#39;s Software 3.0 point is that we may be entering a new computing paradigm.</p><p>The underrated question is not just: what existing workflow gets faster?</p><p>It&#39;s: what can we now build that literally could not exist before?</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：Software 3.0 的核心問題不是「什麼工作流程變快了」，而是「什麼現在可以存在而之前根本不可能」。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>Software 3.0 = 新計算範式，而非更快的舊軟體</li><li>最被低估的問題：「什麼現在能建而以前根本不可能？」（vs. 普遍問的「什麼加速了」）</li><li>此框架改變了建產品的優先序：探索新可能性比優化現有流程更有槓桿</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>Software 1.0（classical code）/ 2.0（ML weights）/ 3.0（LLM native）框架</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>這是 Karpathy 原文核心命題的極度精煉版；對 cc-workspace 有直接使用價值：作為評估任務時「是否應該用 LLM 處理」的判斷框架</li><li>menugen、LLM knowledge base、.md skills 都是此問題的具體答案</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>5/10</td><td>框架性問題，無新增行動細節</td></tr><tr><td>B. 創新性 (20%)</td><td>5/10</td><td>Karpathy 原文精煉，無超越</td></tr><tr><td>C. 證據品質 (20%)</td><td>4/10</td><td>框架命題，無數據</td></tr><tr><td>D. 技術深度 (15%)</td><td>4/10</td><td>概念層面</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>通用框架問題</td></tr><tr><td><strong>加權總分</strong></td><td><strong>5.1/10</strong></td><td>5×0.3+5×0.2+4×0.2+4×0.15+8×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Skip <strong>理由</strong>：總分 5.1，為 Karpathy 原文精煉；核心問題可在 karpathy-principles.md 中作為引言引用</p>',21)])])}const w=a(s,[["render",n]]);export{u as __pageData,w as default};
